const form = $input.first().json.body;

const required = ['employee_id', 'expense_date', 'category', 'amount', 'description'];
const missing = required.filter(f => !form[f]);

if (missing.length > 0) {
  return [{
    json: { success: false, error: `Missing: ${missing.join(', ')}` }
  }];
}

const amount = parseFloat(form.amount);
const gst = parseFloat(form.gst_amount || 0);

if (isNaN(amount) || amount <= 0) {
  return [{
    json: { success: false, error: 'Invalid amount' }
  }];
}

// Generate expense number
const timestamp = Date.now();
const expNumber = `EXP-${form.employee_id}-${timestamp.toString().slice(-6)}`;

return [{
  json: {
    success: true,
    data: {
      expense_number: expNumber,
      employee_id: form.employee_id,
      expense_date: form.expense_date,
      client_id: form.client_id || null,
      category: form.category,
      description: form.description,
      amount: amount,
      gst_amount: gst,
      total_amount: amount + gst,
      receipt_attached: form.has_receipt === 'yes' || form.has_receipt === true,
      project_code: form.project_code || null,
      status: 'Pending'
    }
  }
}

